export default function PayNextPanel() {
  const [phase, setPhase] = useState("idle");
  const [payment, setPayment] = useState(null);
  const [accounts, setAccounts] = useState([]);
  const [error, setError] = useState(null);

  useEffect(() => {
    Promise.all([
      tools.host_listScheduledPayments({}),
      tools.host_listAccounts(),
    ]).then(([paymentsRes, accountsRes]) => {
      const payments = paymentsRes.data || [];
      const accs = accountsRes.data || accountsRes || [];
      setPayment(payments[0] || null);
      setAccounts(accs);
    });
  }, []);

  const checking = accounts.find(
    (a) => a.type === "checking" || (a.name && a.name.toLowerCase().includes("checking"))
  );

  const pay = async () => {
    if (!payment) return;
    setPhase("sending");
    setError(null);
    try {
      const result = await tools.host_transferMoney({
        amount: payment.amountCents,
        recipient_name: payment.payeeName,
        memo: payment.description || payment.payeeName,
      });
      setPhase(result && result.status === "pending-approval" ? "awaiting" : "done");
    } catch (e) {
      setError("Something went wrong. Please try again.");
      setPhase("idle");
    }
  };

  if (!payment) {
    return (
      <div style={{ padding: 20, color: "var(--vendo-color-muted)", fontFamily: "var(--vendo-font-family)" }}>
        No upcoming scheduled payments found.
      </div>
    );
  }

  return (
    <div style={{
      background: "var(--vendo-color-surface)",
      border: "1px solid var(--vendo-color-border)",
      borderRadius: "var(--vendo-radius-medium)",
      padding: 24,
      display: "grid",
      gap: 16,
      fontFamily: "var(--vendo-font-family)",
    }}>
      <div style={{ fontSize: 13, color: "var(--vendo-color-muted)", textTransform: "uppercase", letterSpacing: "0.05em" }}>Pay next scheduled payment</div>
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 16 }}>
        <div>
          <div style={{ fontSize: 12, color: "var(--vendo-color-muted)", marginBottom: 4 }}>Payee</div>
          <div style={{ fontWeight: 600, color: "var(--vendo-color-text)" }}>{payment.payeeName}</div>
        </div>
        <div>
          <div style={{ fontSize: 12, color: "var(--vendo-color-muted)", marginBottom: 4 }}>Amount</div>
          <div style={{ fontWeight: 600, color: "var(--vendo-color-text)" }}>{fmt.money(payment.amountCents)}</div>
        </div>
        <div>
          <div style={{ fontSize: 12, color: "var(--vendo-color-muted)", marginBottom: 4 }}>From</div>
          <div style={{ fontWeight: 600, color: "var(--vendo-color-text)" }}>
            {checking ? checking.name : "Checking account"}
          </div>
        </div>
      </div>
      {error && (
        <div style={{ color: "var(--vendo-color-danger)", fontSize: 13 }}>{error}</div>
      )}
      {phase === "awaiting" && (
        <div style={{
          background: "#FBFBFA",
          border: "1px solid var(--vendo-color-border)",
          borderRadius: "var(--vendo-radius-small)",
          padding: "12px 16px",
          fontSize: 14,
          color: "var(--vendo-color-muted)",
        }}>
          ⏳ Awaiting your approval to complete this payment…
        </div>
      )}
      {phase === "done" && (
        <div style={{
          background: "#FBFBFA",
          border: "1px solid var(--vendo-color-border)",
          borderRadius: "var(--vendo-radius-small)",
          padding: "12px 16px",
          fontSize: 14,
          color: "var(--vendo-color-text)",
        }}>
          ✓ Payment sent to {payment.payeeName}.
        </div>
      )}
      {phase !== "done" && (
        <button
          onClick={pay}
          disabled={phase !== "idle"}
          style={{
            background: phase === "idle" ? "var(--vendo-color-accent)" : "var(--vendo-color-border)",
            color: phase === "idle" ? "var(--vendo-color-accent-text)" : "var(--vendo-color-muted)",
            border: "none",
            borderRadius: "var(--vendo-radius-small)",
            padding: "12px 20px",
            fontFamily: "var(--vendo-font-family)",
            fontSize: 15,
            fontWeight: 600,
            cursor: phase === "idle" ? "pointer" : "not-allowed",
            transition: "background 0.15s",
          }}
        >
          {phase === "sending" ? "Sending…" : phase === "awaiting" ? "Awaiting approval…" : `Pay ${fmt.money(payment.amountCents)} now`}
        </button>
      )}
    </div>
  );
}
